import React, { useState } from 'react';
import { useNotify } from '../App';
import { ApiErrorResponse } from '../types';

interface LoginProps {
  onLogin: (token: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [pin, setPin] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const { notify } = useNotify();

  const mockApiLogin = async (inputPin: string): Promise<{ success: boolean; data?: string; error?: ApiErrorResponse }> => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (inputPin === '1234' || inputPin === 'bot123' || inputPin === '2580') {
      return { success: true, data: inputPin };
    }

    return {
      success: false,
      error: {
        error: {
          code: "AUTH_INVALID_CREDENTIALS",
          message: "The provided PIN does not match any authorized Skynet protocol.",
          details: { attempt_timestamp: new Date().toISOString() }
        }
      }
    };
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isLoading) return;

    setIsLoading(true);
    try {
      const response = await mockApiLogin(pin);
      if (response.success && response.data) {
        onLogin(response.data);
      } else if (response.error) {
        notify(response.error.error.message, "error", "Authentication Failure");
      }
    } catch (err) {
      notify("Critical network failure during authentication handshake.", "error", "System Error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 animate-in fade-in duration-700">
      <div className="w-full max-w-md bg-zinc-900/50 p-8 rounded-2xl border border-emerald-900/30 shadow-2xl shadow-emerald-900/10">
        <div className="flex justify-center mb-8">
          <div className="relative">
            <div className={`absolute -inset-1 rounded-full bg-emerald-500 blur opacity-20 ${isLoading ? 'animate-ping' : 'animate-pulse'}`}></div>
            <div className="relative bg-black p-4 rounded-full border border-emerald-500">
              <svg xmlns="http://www.w3.org/2000/svg" className={`h-12 w-12 ${isLoading ? 'opacity-50' : ''}`} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75l3 3m0 0l3-3m-3 3v-7.5M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
          </div>
        </div>

        <h1 className="text-3xl font-bold text-center mb-2 tracking-tighter text-emerald-400">SKYNETchat MAX</h1>
        <p className="text-emerald-800 text-center mb-8 text-sm uppercase tracking-widest font-bold">Admin Room v4.0.1</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs uppercase tracking-widest text-emerald-700 mb-2 ml-1">Access PIN</label>
            <input
              type="password"
              value={pin}
              onChange={(e) => setPin(e.target.value)}
              placeholder="••••"
              disabled={isLoading}
              className={`w-full bg-black border border-emerald-900/50 p-4 rounded-xl text-center text-2xl tracking-[1rem] focus:outline-none focus:ring-1 focus:ring-emerald-500 transition-all ${isLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
            />
          </div>
          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-emerald-600 hover:bg-emerald-500 disabled:bg-zinc-800 disabled:text-zinc-500 text-black font-bold py-4 rounded-xl transition-all active:scale-[0.98] uppercase tracking-widest text-sm flex items-center justify-center gap-2"
          >
            {isLoading ? (
              <>
                <div className="h-4 w-4 border-2 border-black border-t-transparent animate-spin rounded-full"></div>
                Verifying...
              </>
            ) : "Authenticate"}
          </button>
        </form>

        <p className="text-emerald-900/40 text-[10px] text-center mt-8 uppercase leading-relaxed">
          Proprietary Intelligence Protocol<br/>
          Secure Node Access Required
        </p>
      </div>
    </div>
  );
};

