import React, { useState, useRef, useImperativeHandle, forwardRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage, Type, FunctionDeclaration } from '@google/genai';
import { useNotify } from '../App';
import { FilterCriteria } from '../types';

interface LiveAssistantProps {
  onFilter: (criteria: FilterCriteria) => void;
}

export interface LiveAssistantHandle {
  startSession: () => Promise<void>;
}

const LiveAssistant = forwardRef<LiveAssistantHandle, LiveAssistantProps>(({ onFilter }, ref) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [transcript, setTranscript] = useState<string[]>([]);
  const { notify } = useNotify();

  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useImperativeHandle(ref, () => ({
    startSession: async () => {
      if (!isActive && !isConnecting) {
        await startSession();
      }
    }
  }));

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const createAudioBuffer = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const filterSignalsFunction: FunctionDeclaration = {
    name: 'filterSignals',
    parameters: {
      type: Type.OBJECT,
      description: 'Filter the betting signals display by league or status.',
      properties: {
        league: {
          type: Type.STRING,
          description: 'The name of the football league to filter by (e.g., PSL, BRA-B, Botola). Use null to clear filter.',
        },
        status: {
          type: Type.STRING,
          description: 'The status of the match (pending, success, failed). Use null to clear filter.',
        },
      },
    },
  };

  const startSession = async () => {
    if (!process.env.API_KEY) {
      notify("AI Environment Key is missing. Access restricted.", "error", "Config Error");
      return;
    }

    setIsConnecting(true);
    setTranscript(["Initializing Skynet Voice..."]);

    try {
      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err: any) {
        if (err.name === 'NotAllowedError') {
          notify("Microphone access was denied. Skynet Voice requires audio input.", "error", "Permission Denied");
        } else {
          notify("No functional microphone detected on this device.", "warning", "Hardware Warning");
        }
        setIsConnecting(false);
        return;
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } },
          },
          tools: [{ functionDeclarations: [filterSignalsFunction] }],
          systemInstruction: 'You are SKYNETchat MAX, a professional betting assistant. You provide high-accuracy signals for cards and handicaps. tone: serious, elite, technical. You can filter the dashboard display for the user using the filterSignals tool. If a user asks to see specific matches, use the tool immediately.',
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);
            setTranscript(prev => [...prev, "Connected. Speak now."]);
            notify("Assistant ready for biometric voice analysis.", "success", "AI Uplink Active");

            const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'filterSignals') {
                  const criteria: FilterCriteria = {
                    league: fc.args.league as string | undefined,
                    status: fc.args.status as any,
                  };
                  onFilter(criteria);
                  const result = `Filters applied: League=${criteria.league || 'All'}, Status=${criteria.status || 'All'}`;
                  sessionPromise.then(session => {
                    session.sendToolResponse({
                      functionResponses: {
                        id: fc.id,
                        name: fc.name,
                        response: { result },
                      }
                    });
                  });
                  notify(result, "info", "Display Filtered");
                }
              }
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await createAudioBuffer(decode(audioData), ctx, 24000, 1);
              const sourceNode = ctx.createBufferSource();
              sourceNode.buffer = buffer;
              sourceNode.connect(ctx.destination);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(sourceNode);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            notify("Communication with AI core interrupted.", "error", "Uplink Failure");
            setIsActive(false);
            setIsConnecting(false);
          },
          onclose: (e) => {
            if (e.code !== 1000) {
              notify("AI Session closed unexpectedly.", "warning", "Session Ended");
            }
            setIsActive(false);
            setIsConnecting(false);
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      notify("Critical failure during AI handshake protocol.", "error", "Fatal Error");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
    }
    setIsActive(false);
  };

  return (
    <div className="fixed bottom-24 right-4 z-[9998]">
      <div className={`transition-all duration-500 overflow-hidden ${isActive ? 'w-64 h-80 mb-4' : 'w-0 h-0 opacity-0'}`}>
        <div className="bg-zinc-950 border border-emerald-500/50 rounded-2xl h-full p-4 flex flex-col shadow-2xl">
          <div className="flex justify-between items-center mb-4">
            <span className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest">Skynet Voice Link</span>
            <div className="h-2 w-2 rounded-full bg-emerald-500 animate-ping"></div>
          </div>
          <div className="flex-1 overflow-y-auto space-y-2 mb-4 scrollbar-hide text-xs font-mono">
            {transcript.map((t, i) => (
              <p key={i} className="text-emerald-200 opacity-80">> {t}</p>
            ))}
          </div>
          <div className="h-1 bg-emerald-900/30 rounded-full overflow-hidden">
            <div className="h-full bg-emerald-500 w-full animate-pulse"></div>
          </div>
        </div>
      </div>

      <button
        onClick={isActive ? stopSession : startSession}
        disabled={isConnecting}
        className={`h-16 w-16 rounded-full flex items-center justify-center transition-all shadow-xl active:scale-90 ${
          isActive 
          ? 'bg-red-500 text-white animate-pulse' 
          : 'bg-emerald-500 text-black border-4 border-black/50'
        }`}
      >
        {isConnecting ? (
          <div className="animate-spin h-6 w-6 border-2 border-black border-t-transparent rounded-full"></div>
        ) : isActive ? (
           <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        ) : (
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" viewBox="0 0 24 24" fill="currentColor">
            <path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z" />
            <path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z" />
          </svg>
        )}
      </button>
    </div>
  );
});

export default LiveAssistant;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { MOCK_MATCHES, LEAGUES, MARKETS, generateId } from '../constants';
import { BettingMatch, ApiErrorResponse, SystemLog, FilterCriteria } from '../types';
import LiveAssistant, { LiveAssistantHandle } from './LiveAssistant';
import { useNotify } from '../App';

interface DashboardProps {
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'signals' | 'terminal' | 'database'>('signals');
  const [matches, setMatches] = useState<BettingMatch[]>([]);
  const [logs, setLogs] = useState<SystemLog[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [filter, setFilter] = useState<FilterCriteria>({});
  const { notify } = useNotify();
  const assistantRef = useRef<LiveAssistantHandle>(null);

  // Load from local "Database" on mount
  useEffect(() => {
    const saved = localStorage.getItem('skynet_matches');
    if (saved) {
      setMatches(JSON.parse(saved));
    } else {
      setMatches(MOCK_MATCHES);
    }

    addLog("System initialized. Encrypted link established.", "info");
  }, []);

  // Save to "Database" whenever matches change
  useEffect(() => {
    if (matches.length > 0) {
      localStorage.setItem('skynet_matches', JSON.stringify(matches));
    }
  }, [matches]);

  const addLog = (message: string, level: SystemLog['level'] = 'info') => {
    const newLog: SystemLog = {
      id: generateId(),
      timestamp: new Date().toLocaleTimeString(),
      level,
      message
    };
    setLogs(prev => [newLog, ...prev].slice(0, 50));
  };

  const generateBulkSignals = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    addLog("Initiating bulk generation protocol...", "warn");

    try {
      await new Promise(r => setTimeout(r, 600));
      addLog("Scraping regional data sources...", "info");
      await new Promise(r => setTimeout(r, 1000));

      const newSignals: BettingMatch[] = Array.from({ length: 20 }).map((_, i) => ({
        id: generateId(),
        league: LEAGUES[Math.floor(Math.random() * LEAGUES.length)],
        match: `Match Alpha-${i+1} vs Beta-${i+1}`,
        market: MARKETS[Math.floor(Math.random() * MARKETS.length)],
        meta: `${Math.floor(Math.random() * 5) + 4} cards predicted`,
        timestamp: `${Math.floor(Math.random() * 24).toString().padStart(2, '0')}:00`,
        confidence: 90 + Math.random() * 10,
        status: 'pending'
      }));

      setMatches(newSignals);
      notify("Bulk signal generation finalized. 20 new entries indexed.", "success", "Protocol Success");
      addLog("Signal indexing complete.", "success");
    } catch (err) {
      addLog("Critical failure in generative engine.", "error");
      notify("Failed to generate bulk package. AI core offline.", "error", "Fatal Engine Error");
    } finally {
      setIsSyncing(false);
    }
  };

  const syncData = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    addLog("Scanning for fresh leaks...", "info");

    try {
      await new Promise((resolve, reject) => {
        setTimeout(() => {
          if (Math.random() < 0.05) {
            reject({ error: { code: "SYNC_ERR", message: "Uplink signal lost." } });
          } else { resolve(true); }
        }, 1200);
      });

      const newMatch: BettingMatch = {
        id: generateId(),
        league: LEAGUES[Math.floor(Math.random() * LEAGUES.length)],
        match: 'Priority Leak: Underworld Derby',
        market: 'Over 6.5 cards',
        meta: 'Insider Target: Active',
        timestamp: 'Live',
        confidence: 100,
        status: 'pending'
      };

      setMatches(prev => [newMatch, ...prev].slice(0, 40));
      addLog(`High priority leak found: ${newMatch.match}`, "success");
      notify("Encrypted priority leak intercepted.", "warning", "Security Alert");
    } catch (err: any) {
      addLog("Link sync failed.", "error");
      notify(err.error?.message || "Sync handshake failed.", "error", "Network Failure");
    } finally {
      setIsSyncing(false);
    }
  };

  const displayedMatches = useMemo(() => {
    return matches.filter(m => {
      const leagueMatch = !filter.league || m.league.toLowerCase().includes(filter.league.toLowerCase());
      const statusMatch = !filter.status || m.status === filter.status;
      return leagueMatch && statusMatch;
    });
  }, [matches, filter]);

  return (
    <div className="flex flex-col min-h-screen bg-black pb-24 font-mono">
      {/* Header */}
      <header className="sticky top-0 z-20 bg-black/90 backdrop-blur-xl border-b border-emerald-900/40 p-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="h-10 w-10 bg-emerald-500 rounded-lg flex items-center justify-center text-black font-black text-xl shadow-[0_0_15px_rgba(16,185,129,0.3)]">MAX</div>
          <div>
            <h1 className="text-lg font-black tracking-tighter text-white leading-none">SKYNETchat</h1>
            <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-widest">Protocol v4.0.1_STABLE</p>
          </div>
        </div>
        <button onClick={onLogout} className="px-3 py-1 border border-red-900/30 text-red-500 text-[10px] uppercase font-black hover:bg-red-500/10 transition-colors rounded">Terminate</button>
      </header>

      {/* Navigation Tabs */}
      <nav className="flex bg-zinc-950 border-b border-emerald-900/10 sticky top-[73px] z-10">
        <button 
          onClick={() => setActiveTab('signals')}
          className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'signals' ? 'text-emerald-400 bg-emerald-500/5 border-b-2 border-emerald-500' : 'text-emerald-900'}`}
        >
          Signals
        </button>
        <button 
          onClick={() => setActiveTab('terminal')}
          className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'terminal' ? 'text-emerald-400 bg-emerald-500/5 border-b-2 border-emerald-500' : 'text-emerald-900'}`}
        >
          Terminal
        </button>
        <button 
          onClick={() => setActiveTab('database')}
          className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'database' ? 'text-emerald-400 bg-emerald-500/5 border-b-2 border-emerald-500' : 'text-emerald-900'}`}
        >
          Database
        </button>
      </nav>

      <main className="flex-1 p-4 max-w-4xl mx-auto w-full">
        {activeTab === 'signals' && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <h2 className="text-[10px] uppercase font-black tracking-[0.3em] text-emerald-800">Verified Active Feed</h2>
                {(filter.league || filter.status) && (
                  <button 
                    onClick={() => setFilter({})}
                    className="text-[8px] text-red-500 uppercase font-black border border-red-900/30 px-1 rounded hover:bg-red-500/10"
                  >
                    Clear Filter
                  </button>
                )}
              </div>
              <span className="text-[10px] text-emerald-500 animate-pulse">● LIVE_FEED</span>
            </div>

            {displayedMatches.length > 0 ? displayedMatches.map((m) => (
              <div key={m.id} className="bg-zinc-900/30 border border-emerald-900/20 rounded-xl p-4 relative overflow-hidden group hover:border-emerald-500 transition-all duration-300 shadow-lg">
                <div className="flex justify-between items-start mb-2">
                  <div className="flex flex-col">
                    <span className="text-[9px] text-emerald-600 font-black uppercase tracking-tighter">{m.league}</span>
                    <h3 className="text-white font-bold text-base leading-tight group-hover:text-emerald-400 transition-colors uppercase tracking-tight">{m.match}</h3>
                  </div>
                  <div className={`text-[8px] font-black px-2 py-0.5 rounded border uppercase ${
                    m.status === 'success' ? 'border-emerald-500 text-emerald-500 bg-emerald-500/10' :
                    m.status === 'failed' ? 'border-red-500 text-red-500 bg-red-500/10' :
                    'border-emerald-900/50 text-emerald-700'
                  }`}>
                    {m.status}
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-2 mt-4">
                  <div className="bg-black/60 p-2 rounded border border-emerald-900/10">
                    <p className="text-[8px] uppercase text-emerald-800 font-black mb-0.5">Market Target</p>
                    <p className="text-[11px] font-black text-emerald-200">{m.market}</p>
                  </div>
                  <div className="bg-black/60 p-2 rounded border border-emerald-900/10">
                    <p className="text-[8px] uppercase text-emerald-800 font-black mb-0.5">Confidence</p>
                    <p className="text-[11px] font-black text-emerald-400">{m.confidence.toFixed(1)}%</p>
                  </div>
                </div>

                <div className="flex items-center justify-between mt-4 pt-3 border-t border-emerald-900/10">
                  <div className="flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                    <span className="text-[10px] text-emerald-800 font-black uppercase">{m.timestamp}</span>
                  </div>
                  <div className="text-[10px] text-emerald-400 font-bold italic tracking-tighter">
                    {m.meta}
                  </div>
                </div>
              </div>
            )) : (
              <div className="py-20 text-center opacity-40">
                <p className="text-xs uppercase font-black tracking-widest">No matches match current filter protocol.</p>
              </div>
            )}
          </div>
        )}

        {activeTab === 'terminal' && (
          <div className="bg-zinc-950 border border-emerald-900/30 rounded-xl overflow-hidden h-[60vh] flex flex-col shadow-2xl animate-in fade-in zoom-in-95 duration-300">
            <div className="bg-emerald-900/10 p-2 border-b border-emerald-900/30 flex items-center justify-between">
              <span className="text-[9px] font-black uppercase tracking-widest text-emerald-500">Predictive Engine v2.0</span>
              <div className="flex gap-1">
                <div className="w-2 h-2 rounded-full bg-red-500/50"></div>
                <div className="w-2 h-2 rounded-full bg-amber-500/50"></div>
                <div className="w-2 h-2 rounded-full bg-emerald-500/50"></div>
              </div>
            </div>
            <div className="flex-1 p-4 overflow-y-auto space-y-1 font-mono text-[10px] scrollbar-hide">
              {logs.map((log) => (
                <div key={log.id} className="flex gap-3">
                  <span className="text-emerald-900 shrink-0">[{log.timestamp}]</span>
                  <span className={`${
                    log.level === 'error' ? 'text-red-500' :
                    log.level === 'warn' ? 'text-amber-500' :
                    log.level === 'success' ? 'text-emerald-400' :
                    'text-emerald-700'
                  }`}>
                    {log.level.toUpperCase()}: {log.message}
                  </span>
                </div>
              ))}
              <div className="animate-pulse text-emerald-500">_</div>
            </div>
            <div className="p-4 border-t border-emerald-900/10">
              <button 
                onClick={generateBulkSignals}
                disabled={isSyncing}
                className="w-full py-3 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-black font-black uppercase tracking-[0.2em] text-[10px] rounded transition-all active:scale-95"
              >
                {isSyncing ? "EXECUTING PROTOCOL..." : "FORCE DAILY 20 GENERATION"}
              </button>
            </div>
          </div>
        )}

        {activeTab === 'database' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-zinc-900/20 border border-emerald-900/10 rounded-xl p-6 text-center">
              <div className="mb-4 inline-block p-4 rounded-full bg-emerald-500/10 border border-emerald-500/20">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 7v10c0 2.21 3.582 4 8 4s8-1.791 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.791 8-4M4 7c0-2.21 3.582-4 8-4s8 1.791 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.791-8-4" />
                </svg>
              </div>
              <h2 className="text-white font-black uppercase tracking-widest text-sm mb-2">Encrypted Local Storage</h2>
              <div className="grid grid-cols-2 gap-4 text-left mb-6">
                <div className="bg-black/50 p-3 rounded border border-emerald-900/10">
                  <p className="text-[8px] text-emerald-800 uppercase font-black mb-1">Records</p>
                  <p className="text-white font-bold">{matches.length}</p>
                </div>
                <div className="bg-black/50 p-3 rounded border border-emerald-900/10">
                  <p className="text-[8px] text-emerald-800 uppercase font-black mb-1">Health</p>
                  <p className="text-emerald-400 font-bold uppercase">Optimal</p>
                </div>
              </div>

              {/* Test Notification Area */}
              <div className="mt-8 border-t border-emerald-900/10 pt-6">
                <h3 className="text-[10px] text-emerald-700 uppercase font-black mb-4 tracking-widest">System Diagnostics (Test Notifications)</h3>
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={() => notify("The automated test confirmed system integrity.", "success", "Diagnostic Success")}
                    className="p-2 bg-emerald-900/20 hover:bg-emerald-900/40 border border-emerald-900/30 text-emerald-400 text-[9px] uppercase font-bold rounded transition-colors"
                  >
                    Test Success
                  </button>
                  <button 
                    onClick={() => notify("Authorized terminal accessed from unknown node.", "info", "Security Log")}
                    className="p-2 bg-sky-900/20 hover:bg-sky-900/40 border border-sky-900/30 text-sky-400 text-[9px] uppercase font-bold rounded transition-colors"
                  >
                    Test Info
                  </button>
                  <button 
                    onClick={() => notify("Low latency detected on dark-web uplink.", "warning", "Latency Alert")}
                    className="p-2 bg-amber-900/20 hover:bg-amber-900/40 border border-amber-900/30 text-amber-400 text-[9px] uppercase font-bold rounded transition-colors"
                  >
                    Test Warning
                  </button>
                  <button 
                    onClick={() => notify("Cryptographic handshake failed on local node.", "error", "Fatal Auth Error")}
                    className="p-2 bg-red-900/20 hover:bg-red-900/40 border border-red-900/30 text-red-400 text-[9px] uppercase font-bold rounded transition-colors"
                  >
                    Test Error
                  </button>
                </div>
              </div>

              <button 
                onClick={() => {
                  localStorage.removeItem('skynet_matches');
                  setMatches(MOCK_MATCHES);
                  notify("All local records have been shredded.", "warning", "Wipe Complete");
                  addLog("Database reset triggered by administrator.", "warn");
                }}
                className="mt-8 text-[10px] text-red-900 hover:text-red-500 uppercase font-black transition-colors"
              >
                [ Wipe Data Terminal ]
              </button>
            </div>
          </div>
        )}
      </main>

      <LiveAssistant ref={assistantRef} onFilter={setFilter} />

      <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black via-zinc-950 to-transparent pointer-events-none z-30">
        <div className="flex gap-3 max-w-4xl mx-auto">
          <button 
            onClick={syncData}
            disabled={isSyncing}
            className="flex-1 pointer-events-auto bg-emerald-500 hover:bg-emerald-400 disabled:bg-zinc-800 disabled:text-zinc-600 text-black font-black py-4 rounded-2xl shadow-[0_10px_30px_rgba(16,185,129,0.2)] active:scale-95 transition-all uppercase tracking-[0.2em] text-[10px] sm:text-xs"
          >
            {isSyncing ? 'LINKING...' : 'QUICK SYNC SIGNAL'}
          </button>
          <button 
            onClick={() => assistantRef.current?.startSession()}
            className="flex-1 pointer-events-auto bg-zinc-900 hover:bg-zinc-800 border border-emerald-500/30 text-emerald-400 font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all uppercase tracking-[0.2em] text-[10px] sm:text-xs flex items-center justify-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 006 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
            </svg>
            VOICE COMMAND
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
